@page "/recipes"
@page "/recipes/{Category}"

<PageTitle>Recipes - @(Category ?? "All Categories")</PageTitle>

<h1>@GetCategoryTitle()</h1>

@if (Category is null)
{
    <p>Select a category from the homepage or use the links below:</p>
    <ul>
        <li><a href="recipes/appetizers">Appetizers</a></li>
        <li><a href="recipes/main-courses">Main Courses</a></li>
        <li><a href="recipes/desserts">Desserts</a></li>
        <li><a href="recipes/beverages">Beverages</a></li>
        <li><a href="recipes/baking">Baking</a></li>
        <li><a href="recipes/vegetarian">Vegetarian</a></li>
    </ul>
}
else
{
    <div class="row">
        @foreach (var recipe in GetRecipesForCategory())
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? Category { get; set; }

    private string GetCategoryTitle() => Category switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        "beverages" => "🥤 Beverages",
        "baking" => "🍞 Baking",
        "vegetarian" => "🥬 Vegetarian",
        _ => "Browse Recipes"
    };

    private List<RecipeSummary> GetRecipesForCategory() => Category switch
    {
        "appetizers" => new()
        {
            new("bruschetta", "Classic Bruschetta", "Toasted bread with fresh tomatoes, basil, and garlic."),
            new("spinach-dip", "Spinach Artichoke Dip", "Creamy warm dip with spinach and artichoke hearts."),
        },
        "main-courses" => new()
        {
            new("spaghetti-carbonara", "Spaghetti Carbonara", "Classic Italian pasta with eggs, cheese, and pancetta."),
            new("chicken-tikka", "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato sauce."),
        },
        "desserts" => new()
        {
            new("chocolate-cake", "Chocolate Lava Cake", "Rich molten chocolate cake with a gooey center."),
            new("tiramisu", "Tiramisu", "Italian coffee-flavored layered dessert."),
        },
        "beverages" => new()
        {
            new("mango-smoothie", "Mango Smoothie", "Fresh mango blended with yogurt and honey."),
            new("iced-coffee", "Iced Coffee", "Cold brew coffee with milk and vanilla."),
        },
        "baking" => new()
        {
            new("sourdough", "Sourdough Bread", "Artisan sourdough with a crispy crust."),
            new("cinnamon-rolls", "Cinnamon Rolls", "Soft rolls with cinnamon sugar and cream cheese frosting."),
        },
        "vegetarian" => new()
        {
            new("veggie-stir-fry", "Vegetable Stir Fry", "Colorful vegetables in a savory soy-ginger sauce."),
            new("mushroom-risotto", "Mushroom Risotto", "Creamy arborio rice with wild mushrooms and parmesan."),
        },
        _ => new()
    };

    private record RecipeSummary(string Id, string Title, string Description);
}

@rendermode InteractiveServer

<div class="star-rating my-3">
    <span class="fw-bold me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= CurrentRating ? "selected" : "")"
              @onclick="() => SetRating(star)"
              role="button"
              title="@star star(s)">
            @(star <= CurrentRating ? "★" : "☆")
        </span>
    }
    @if (CurrentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @CurrentRating/5</span>
    }
</div>

<style>
    .star-rating .star {
        font-size: 1.5rem;
        cursor: pointer;
        color: #ffc107;
        transition: transform 0.1s;
    }
    .star-rating .star:hover {
        transform: scale(1.2);
    }
    .star-rating .star.selected {
        color: #ffc107;
    }
</style>

@code {
    private int CurrentRating { get; set; }

    private void SetRating(int rating)
    {
        CurrentRating = rating;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been submitted successfully.</p>
        <button class="btn btn-primary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients"
                           placeholder="Enter each ingredient on a new line" />
            <ValidationMessage For="() => Model.Ingredients" />
            <div class="form-text">Enter each ingredient on a separate line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps"
                           placeholder="Enter each step on a new line" />
            <ValidationMessage For="() => Model.Steps" />
            <div class="form-text">Enter each step on a separate line.</div>
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new();
        IsSubmitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title cannot exceed 100 characters.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = "";
    }
}

